from __future__ import annotations
import random
from typing import List
from cac.core.schemas import AccountDossier, SourceItem, SourceType
from .profiles import TASKS, task_slots
MISSING_TYPES=("none","missing_exact","missing_operational","missing_authority","missing_status")
def src(account,entity,st,sid,title,text,topics,tags,slots,authority=.8,days=10,pos=False,neg=False,exact=False,distractor=False,structured=None):
    return SourceItem(source_id=f"{account}_{sid}",account_id=account,entity=entity,source_type=st,title=title,text=text,freshness_days=days,authority=authority,topics=list(topics),risk_tags=list(tags),structured=structured or {},gold_slots=list(slots),gold_positive=pos,gold_negative=neg,gold_exact_required=exact,is_distractor=distractor)
def generate_decision_dossiers(n:int=5,distractors:int=12,seed:int=42,task_types:List[str]|None=None,missing_rate:float=.25,metadata_noise:float=.1)->List[AccountDossier]:
    rng=random.Random(seed+n*31+distractors*7+int(metadata_noise*100)); task_types=task_types or list(TASKS); out=[]
    for i in range(n):
        for task in task_types:
            account=f"{task[:3]}_{i:04d}"; entity=f"{task.replace('_',' ').title()} Entity {i:04d}"; missing_type=MISSING_TYPES[(i+len(task))%len(MISSING_TYPES)] if rng.random()<missing_rate else "none"
            sources=make_task_sources(task,account,entity,missing_type)+make_distractors(account,entity,distractors,rng); apply_noise(sources,rng,metadata_noise)
            present=sorted({slot for s in sources for slot in s.gold_slots}); required=[s.name for s in task_slots(task)]; missing=[s for s in required if s not in present]
            out.append(AccountDossier(account_id=account,entity=entity,sources=sources,present_gold_slots=present,missing_gold_slots=missing,has_contradiction=True,metadata_mode=f"noise_{metadata_noise}",distractors=distractors,missing_case=bool(missing),missing_case_type=missing_type))
    return out
def make_task_sources(task,account,entity,missing_type):
    if task=="renewal_risk":
        sources=[src(account,entity,SourceType.CRM,"crm","CRM green","CRM marks account green and on track.",["crm","health","renewal","status"],["subjective_status"],["crm_health_status"],.55,14,True),src(account,entity,SourceType.BILLING,"billing","Billing overdue","Invoice is 52 days overdue; two prior invoices were late.",["billing","payment","overdue"],["payment_default","operational_signal"],["billing_status"],.97,4,False,True,False,False,{"overdue_days":52}),src(account,entity,SourceType.SUPPORT,"support","P1 support trend","Three unresolved P1 escalations mention renewal risk.",["support","escalation","p1","outage"],["operational_signal","customer_unhappy"],["support_trend"],.9,8,False,True),src(account,entity,SourceType.CONTRACT,"contract","Termination clause","Non-payment of undisputed fees for more than forty-five days after notice constitutes material breach and may permit termination after a thirty-day cure period.",["contract","termination","payment","cure"],["termination","payment_default","obligation","exact_wording_required"],["contract_terms"],.99,180,False,True,True),src(account,entity,SourceType.EMAIL,"exec","Exec sponsor","VP Operations wrote: We cannot recommend renewal unless outages are fixed before review.",["email","executive","renewal"],["executive_commitment","customer_unhappy","exact_wording_required"],["executive_signal"],.86,12,False,True,True)]
        omit={"missing_exact":"contract_terms","missing_operational":"support_trend","missing_authority":"executive_signal","missing_status":"crm_health_status"}.get(missing_type)
    elif task=="security_exception":
        sources=[src(account,entity,SourceType.SECURITY,"gap","Control gap","Security review identifies missing SAML enforcement and audit-log retention gap.",["security","gap","control"],["control_gap","risk"],["control_gap"],.95,5,False,True),src(account,entity,SourceType.INTERNAL_NOTE,"biz","Business justification","Business owner says exception is needed for regulated customer launch.",["business","justification"],["business_need"],["business_justification"],.75,9,True),src(account,entity,SourceType.SECURITY,"comp","Compensating control","Compensating control: daily access review and temporary IP allowlist.",["security","compensating","control"],["mitigation"],["compensating_control"],.9,7,True),src(account,entity,SourceType.EMAIL,"approval","Approval authority","CISO delegate wrote: I approve this exception only until 2026-07-31 if daily access evidence is retained.",["email","approval","authority"],["approval","authority","exact_wording_required"],["approval_authority"],.92,3,True,False,True),src(account,entity,SourceType.SECURITY,"expiry","Review date","Exception expires 2026-07-31 and must be reviewed by security.",["security","expiration","review"],["expiry"],["expiration_or_review_date"],.88,3,True)]
        omit={"missing_exact":"approval_authority","missing_operational":"compensating_control","missing_authority":"approval_authority","missing_status":"expiration_or_review_date"}.get(missing_type)
    elif task=="contract_termination":
        sources=[src(account,entity,SourceType.CONTRACT,"term","Termination for cause","Either party may terminate only if material breach remains uncured thirty days after written notice.",["contract","termination","cure","breach"],["termination","cure","breach","exact_wording_required"],["termination_clause"],.99,220,False,False,True),src(account,entity,SourceType.BILLING,"pay","Payment default","Undisputed invoice is 61 days overdue after notice was sent.",["billing","payment","overdue"],["payment_default","breach"],["breach_event","payment_status"],.96,2,False,True,False,False,{"overdue_days":61}),src(account,entity,SourceType.EMAIL,"notice","Cure notice","Legal ops sent written cure notice; no cure confirmation is recorded.",["email","notice","cure"],["notice","breach"],["notice_or_cure_status"],.91,6,False,True),src(account,entity,SourceType.EMAIL,"counterparty","Counterparty position","Customer counsel wrote: We dispute termination because no valid notice was received by our legal notice address.",["email","counterparty","position"],["dispute","exact_wording_required"],["counterparty_position"],.86,4,True,False,True)]
        omit={"missing_exact":"termination_clause","missing_operational":"breach_event","missing_authority":"counterparty_position","missing_status":"notice_or_cure_status"}.get(missing_type)
    else:
        sources=[src(account,entity,SourceType.INTERNAL_NOTE,"timeline","Incident timeline","Timeline: deploy 09:05, alerts 09:22, rollback 10:10, recovery 10:38.",["incident","timeline","status"],["incident"],["incident_timeline"],.88,3,False,True),src(account,entity,SourceType.SUPPORT,"impact","Customer impact","Three enterprise customers lost export access for 73 minutes.",["support","customer","impact"],["customer_impact"],["customer_impact"],.9,3,False,True),src(account,entity,SourceType.INTERNAL_NOTE,"root","Root cause","Root cause was a schema migration that bypassed export canary checks.",["root","cause","incident"],["root_cause"],["root_cause"],.86,4,False,True),src(account,entity,SourceType.EMAIL,"remed","Remediation commitment","VP Eng wrote: We will add export canary gates before the next deploy and complete owner review by Friday.",["email","remediation","commitment"],["commitment","remediation","exact_wording_required"],["remediation_commitment"],.84,2,True,False,True),src(account,entity,SourceType.CRM,"status","Conflicting status","CRM says customer impact was minor and no escalation is expected.",["crm","status","conflict"],["subjective_status"],["conflicting_status"],.5,2,True)]
        omit={"missing_exact":"remediation_commitment","missing_operational":"customer_impact","missing_authority":"remediation_commitment","missing_status":"conflicting_status"}.get(missing_type)
    return [s for s in sources if not (omit and omit in s.gold_slots)]
def make_distractors(account,entity,count,rng):
    templates=[(SourceType.SLACK,"Slack optimism","Someone says this is probably fine, no source attached.",["slack","status"],["speculation"]),(SourceType.CONTRACT,"Generic DPA","Data processing safeguards are commercially reasonable; this section does not modify obligations.",["contract","security"],["generic_contract"]),(SourceType.SUPPORT,"Minor ticket","Low-priority UI ticket closed successfully with no risk mentioned.",["support","ticket"],["distractor"]),(SourceType.INTERNAL_NOTE,"Training note","Enablement materials requested for next quarter.",["training","admin"],["noise"]),(SourceType.EMAIL,"Old positive","Old note says leadership was optimistic six months ago.",["email","status"],["stale_positive_signal"]),(SourceType.SECURITY,"Unrelated scan","Scanner found unrelated medium issue in a sandbox.",["security","review"],["noise"])]
    return [src(account,entity,st,f"distractor_{j:03d}",title,text,topics,tags,[],authority=rng.choice([.25,.45,.6,.8]),days=rng.randint(5,300),distractor=True,pos=("optimistic" in text)) for j,(st,title,text,topics,tags) in ((j,templates[j%len(templates)]) for j in range(count))]
def apply_noise(sources,rng,rate):
    for s in sources:
        if rng.random()<rate and s.risk_tags: s.risk_tags=s.risk_tags[:-1]
        if rng.random()<rate and s.topics: s.topics=s.topics[:-1]
        if rng.random()<rate: s.freshness_days+=rng.randint(60,180)
        if rng.random()<rate/2: s.risk_tags.append(rng.choice(["noise","termination","security","customer_unhappy","payment_default"]))
